import{_ as t,o as a,c as n,a2 as o}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"ForgeCode — Multi-Agent Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/forgecode/architecture.md","filePath":"research/agents/forgecode/architecture.md"}'),i={name:"research/agents/forgecode/architecture.md"};function s(r,e,l,d,c,h){return a(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="forgecode-—-multi-agent-architecture" tabindex="-1">ForgeCode — Multi-Agent Architecture <a class="header-anchor" href="#forgecode-—-multi-agent-architecture" aria-label="Permalink to &quot;ForgeCode — Multi-Agent Architecture&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>ForgeCode&#39;s architecture is fundamentally different from single-loop coding agents like Claude Code or Aider. Instead of one monolithic agent with full context and all tools, ForgeCode uses <strong>three specialized sub-agents</strong> — each with distinct access levels, purposes, and bounded context windows. A proprietary runtime layer (ForgeCode Services) sits beneath all three, providing shared infrastructure.</p><h2 id="the-three-sub-agents" tabindex="-1">The Three Sub-Agents <a class="header-anchor" href="#the-three-sub-agents" aria-label="Permalink to &quot;The Three Sub-Agents&quot;">​</a></h2><h3 id="forge-implementation-agent" tabindex="-1">FORGE (Implementation Agent) <a class="header-anchor" href="#forge-implementation-agent" aria-label="Permalink to &quot;FORGE (Implementation Agent)&quot;">​</a></h3><ul><li><strong>Access</strong>: Read + Write</li><li><strong>Purpose</strong>: Direct implementation — modifying files, creating code, executing shell commands</li><li><strong>Active by default</strong> when the user starts a session</li><li><strong>Ideal for</strong>: Quick fixes, feature implementation, refactoring, routine tasks</li><li><strong>Invocation</strong>: <code>:forge</code> or <code>/forge</code> from ZSH</li></ul><p>Forge is the hands-on builder. It has full system access (same permissions as the user) and can create, edit, and delete files, run tests, execute arbitrary shell commands. It operates like a junior developer who can write code fast but benefits from a plan.</p><h3 id="muse-planning-analysis-agent" tabindex="-1">MUSE (Planning &amp; Analysis Agent) <a class="header-anchor" href="#muse-planning-analysis-agent" aria-label="Permalink to &quot;MUSE (Planning &amp; Analysis Agent)&quot;">​</a></h3><ul><li><strong>Access</strong>: Read-only</li><li><strong>Purpose</strong>: Strategic planning, impact analysis, architecture review</li><li><strong>Ideal for</strong>: Complex refactoring plans, understanding scope before changes, critical systems review</li><li><strong>Invocation</strong>: <code>:muse</code> or <code>/muse</code></li></ul><p>Muse deliberately operates in read-only mode. This constraint is a feature: by preventing Muse from making changes, the system ensures that planning and analysis happen without side effects. Muse creates detailed implementation plans, identifies risks, and proposes solutions. It cannot touch your code — it can only think about it.</p><h3 id="sage-research-investigation-agent" tabindex="-1">SAGE (Research &amp; Investigation Agent) <a class="header-anchor" href="#sage-research-investigation-agent" aria-label="Permalink to &quot;SAGE (Research &amp; Investigation Agent)&quot;">​</a></h3><ul><li><strong>Access</strong>: Read-only</li><li><strong>Purpose</strong>: Deep codebase research, dependency tracing, architecture mapping</li><li><strong>Not user-facing</strong> — used internally by both Forge and Muse</li><li><strong>Invocation</strong>: Automatic (called transparently by other agents when they need codebase understanding)</li></ul><p>Sage is the internal research engine. When Forge or Muse needs to understand how a codebase works — trace a bug across files, map module dependencies, or find the right entry point — they delegate to Sage. The user never interacts with Sage directly; it operates behind the scenes.</p><h2 id="bounded-context-model" tabindex="-1">Bounded Context Model <a class="header-anchor" href="#bounded-context-model" aria-label="Permalink to &quot;Bounded Context Model&quot;">​</a></h2><p>A core architectural principle is <strong>bounded context</strong>: each sub-agent operates on the minimal, relevant context for its current task rather than stuffing everything into one massive context window.</p><h3 id="how-bounded-context-works" tabindex="-1">How Bounded Context Works <a class="header-anchor" href="#how-bounded-context-works" aria-label="Permalink to &quot;How Bounded Context Works&quot;">​</a></h3><ol><li><p><strong>Task decomposition</strong>: When a complex task arrives, it is decomposed into sub-tasks. Research tasks go to Sage, planning tasks go to Muse, implementation tasks go to Forge.</p></li><li><p><strong>Context isolation</strong>: Each sub-agent receives only the context relevant to its specific sub-task. Sage gets the files and symbols it needs to investigate. Muse gets the analysis results and task description. Forge gets the plan and the specific files to modify.</p></li><li><p><strong>Context doesn&#39;t bloat across agents</strong>: If Sage researches 50 files to find the right entry point, only the relevant findings (not all 50 files) are passed to the next agent. This prevents the context window explosion that plagues single-loop agents on large codebases.</p></li><li><p><strong>Conversation context is preserved when switching agents</strong>: The user&#39;s conversation history carries across agent switches, but each agent&#39;s internal working context remains bounded.</p></li></ol><h3 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>Single-loop agents like Claude Code operate with one growing context window. As a session progresses, the context fills with tool results, file contents, and conversation history. By the time the agent is executing step 15 of a complex task, it may be working with degraded context quality.</p><p>ForgeCode&#39;s approach keeps each agent&#39;s context lean:</p><ul><li>Sage investigates with focused read-only context</li><li>Muse plans with research results + task description</li><li>Forge executes with plan + targeted file contents</li></ul><h2 id="forgecode-services-runtime-layer" tabindex="-1">ForgeCode Services (Runtime Layer) <a class="header-anchor" href="#forgecode-services-runtime-layer" aria-label="Permalink to &quot;ForgeCode Services (Runtime Layer)&quot;">​</a></h2><p>ForgeCode Services is the proprietary infrastructure that sits beneath all three agents. It provides five key capabilities:</p><h3 id="_1-context-engine-semantic-entry-point-discovery" tabindex="-1">1. Context Engine (Semantic Entry-Point Discovery) <a class="header-anchor" href="#_1-context-engine-semantic-entry-point-discovery" aria-label="Permalink to &quot;1. Context Engine (Semantic Entry-Point Discovery)&quot;">​</a></h3><p>Before any agent starts exploring a codebase, a lightweight semantic pass identifies the most likely starting files and functions based on the task description. This converts random codebase exploration into directed traversal.</p><ul><li>Uses semantic search (<code>sem_search</code> tool) over an indexed project</li><li>Achieves &quot;up to 93% fewer tokens&quot; compared to naive exploration</li><li>Requires <code>:sync</code> to index the project initially</li></ul><p>The context engine solves a critical problem identified in TermBench evaluation: <strong>context size is a multiplier on the right entry point, not a substitute for it</strong>. Finding the right file early matters more than having a larger context window.</p><h3 id="_2-dynamic-skill-loading" tabindex="-1">2. Dynamic Skill Loading <a class="header-anchor" href="#_2-dynamic-skill-loading" aria-label="Permalink to &quot;2. Dynamic Skill Loading&quot;">​</a></h3><p>Skills are specialized instruction sets for particular task types. They are loaded only when the task profile requires them:</p><ul><li>A test-writing task loads the testing skill</li><li>A debugging task loads the debugging skill</li><li>A refactoring task loads the refactoring skill</li></ul><p>This keeps the system prompt lean and relevant. Skills that aren&#39;t needed don&#39;t consume context.</p><h3 id="_3-tool-call-correction-layer" tabindex="-1">3. Tool-Call Correction Layer <a class="header-anchor" href="#_3-tool-call-correction-layer" aria-label="Permalink to &quot;3. Tool-Call Correction Layer&quot;">​</a></h3><p>A heuristic + static analysis layer intercepts tool calls before dispatch:</p><ul><li>Validates argument shapes against schemas</li><li>Catches common error patterns (wrong field names, nested schema confusion)</li><li>Auto-corrects where possible rather than failing silently</li></ul><p>This is especially important for local/open-weight models that have higher tool-call error rates.</p><h3 id="_4-todo-enforcement" tabindex="-1">4. Todo Enforcement <a class="header-anchor" href="#_4-todo-enforcement" aria-label="Permalink to &quot;4. Todo Enforcement&quot;">​</a></h3><p>The <code>todo_write</code> tool is made non-optional for decomposed tasks:</p><ul><li>Multi-step tasks must have explicit task items created</li><li>Each item must be updated as progress is made</li><li>Completion must be explicitly marked</li></ul><p>The runtime treats failure to maintain task state as a reliability failure, not a stylistic choice.</p><h3 id="_5-progressive-reasoning-budget-control" tabindex="-1">5. Progressive Reasoning Budget Control <a class="header-anchor" href="#_5-progressive-reasoning-budget-control" aria-label="Permalink to &quot;5. Progressive Reasoning Budget Control&quot;">​</a></h3><p>The reasoning budget (thinking tokens) is managed automatically based on turn count:</p><table tabindex="0"><thead><tr><th>Phase</th><th>Messages</th><th>Thinking Budget</th></tr></thead><tbody><tr><td>Planning</td><td>First 10 assistant messages</td><td>Very high</td></tr><tr><td>Execution</td><td>Messages 11+</td><td>Low (by default)</td></tr><tr><td>Verification</td><td>When verification skill is called</td><td>Switches back to high</td></tr></tbody></table><p>This prevents the agent from over-deliberating during execution while ensuring deep reasoning at critical decision points.</p><h2 id="model-routing" tabindex="-1">Model Routing <a class="header-anchor" href="#model-routing" aria-label="Permalink to &quot;Model Routing&quot;">​</a></h2><p>ForgeCode supports mixing models within a single session:</p><ul><li><strong>Thinking models</strong> (Opus 4, O3, DeepSeek-R1): Complex planning, architecture decisions</li><li><strong>Fast models</strong> (Sonnet, GPT-4.1, Grok-4): Routine edits, quick fixes, execution</li><li><strong>Large-context models</strong> (Gemini 3.1 Pro): Big file analysis, cross-file reasoning</li></ul><p>Users switch with <code>:model</code> — conversation context is preserved across model changes. The recommended workflow is to use a reasoning model during the Muse planning phase, then switch to a fast model for Forge execution.</p><h2 id="sub-agent-parallelization" tabindex="-1">Sub-Agent Parallelization <a class="header-anchor" href="#sub-agent-parallelization" aria-label="Permalink to &quot;Sub-Agent Parallelization&quot;">​</a></h2><p>Low-complexity work is delegated to sub-agents running with minimal thinking budget. This keeps the main agent&#39;s latency low:</p><ul><li>File reads, pattern searches, and routine edits run as parallel sub-agent calls</li><li>The main agent reserves its thinking budget for high-value decisions</li><li>This speed architecture was a key factor in reaching 78.4% → 81.8% on TermBench</li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Agents are configured via <code>forge.yaml</code> and <code>AGENTS.md</code>:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># forge.yaml</span></span>
<span class="line"><span style="color:#89B4FA;">model</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;claude-sonnet-4&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">custom_rules</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">  Always add error handling.</span></span>
<span class="line"><span style="color:#A6E3A1;">  Include unit tests for new functions.</span></span>
<span class="line"><span style="color:#89B4FA;">max_walker_depth</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 3</span></span>
<span class="line"><span style="color:#89B4FA;">max_requests_per_turn</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 50</span></span></code></pre></div><p><code>AGENTS.md</code> in the project root injects team-specific guidelines into the system prompt for all agents. Custom agents can also be defined for domain-specific workflows.</p><h2 id="architecture-comparison" tabindex="-1">Architecture Comparison <a class="header-anchor" href="#architecture-comparison" aria-label="Permalink to &quot;Architecture Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>ForgeCode</th><th>Claude Code</th><th>Aider</th></tr></thead><tbody><tr><td>Agent count</td><td>3 specialized</td><td>1 monolithic</td><td>1 monolithic</td></tr><tr><td>Context model</td><td>Bounded per agent</td><td>Single growing window</td><td>Single growing window</td></tr><tr><td>Shell integration</td><td>ZSH-native (<code>:</code>)</td><td>Separate REPL</td><td>Separate REPL</td></tr><tr><td>Tool corrections</td><td>Auto-correction layer</td><td>None</td><td>None</td></tr><tr><td>Model switching</td><td>Mid-session, preserved context</td><td>Single model</td><td>Single model</td></tr><tr><td>Verification enforcement</td><td>Programmatic</td><td>Prompt-based</td><td>None</td></tr><tr><td>Open source</td><td>Core yes, services no</td><td>No</td><td>Yes</td></tr></tbody></table>`,56)])])}const u=t(i,[["render",s]]);export{p as __pageData,u as default};
